interface SidebarProps {
    className?: string;
    auth?: {
        user: {
            id: number;
            name: string;
            email: string;
            type: string; // Add type to user object
        };
    };
}

interface PageProps {
    url: string;
}

export function AppSidebar({ className, auth }: SidebarProps) {
    const { url } = usePage<PageProps>();
    const [isHovered, setIsHovered] = useState(false);
    const [openMenu, setOpenMenu] = useState<string | null>(null);

    // Filter menu items based on user type
    const filteredMenuItems = menuItems.filter(item => {
        if (!auth?.user?.type) return false; // No user type, show nothing
        return item.type.includes(auth.user.type);
    });

    const handleTouch = (e: React.TouchEvent, id: string, hasChildren: boolean) => {
        if (hasChildren) {
            e.preventDefault();
            setOpenMenu(openMenu === id ? null : id);
        }
    };

    return (
    <>
      {/* Mobile Bottom Menu */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 h-16 bg-white border-t border-gray-200 z-50">
        <div className="flex overflow-x-auto scrollbar-hide px-2 h-full">
          {filteredMenuItems.map((item) => { // Use filteredMenuItems here
            const isActive = url === item.href;

            return (
              <div key={item.id} className="relative flex flex-col items-center justify-center min-w-[60px]">
                {item.children ? (
                  <HoverCard open={openMenu === item.id} onOpenChange={(o) => !o && setOpenMenu(null)}>
                    <HoverCardTrigger
                      asChild
                      onTouchStart={(e) => handleTouch(e, item.id, true)}
                    >
                      <button
                        className={cn(
                          "flex flex-col items-center justify-center p-2",
                          isActive ? "text-green-700" : "text-gray-600 hover:text-green-600"
                        )}
                      >
                        <div className="w-5 h-5 flex items-center justify-center">
                          {item.icon}
                        </div>
                      </button>
                    </HoverCardTrigger>
                    <HoverCardContent
                      align="center"
                      side="top"
                      className="bg-white shadow-md rounded p-2"
                    >
                      {item.children.map((child) => (
                        <Link
                          key={child.href}
                          href={child.href}
                          className="block px-3 py-1 rounded hover:bg-gray-100"
                        >
                          {child.label}
                        </Link>
                      ))}
                    </HoverCardContent>
                  </HoverCard>
                ) : (
                  <Link
                    href={item.href}
                    onTouchStart={(e) => handleTouch(e, item.id, false)}
                    className={cn(
                      "flex flex-col items-center justify-center p-2",
                      isActive ? "text-green-700" : "text-gray-600 hover:text-green-600"
                    )}
                  >
                    <Tooltip>
                      <TooltipTrigger asChild>
                        <div className="w-5 h-5 flex items-center justify-center">
                          {item.icon}
                        </div>
                      </TooltipTrigger>
                      <TooltipContent>
                        <p>{item.label}</p>
                      </TooltipContent>
                    </Tooltip>
                  </Link>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Desktop Sidebar */}
      <div
        className={cn(
          "hidden md:flex w-[100px] h-screen flex-col items-center",
          "bg-white dark:bg-neutral-900 z-50",
          "overflow-hidden",
          className
        )}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        {/* Logo */}
        <div className="mt-1 mb-2 p-2 border-b">
          <div className="w-12 h-12 flex items-center justify-center">
            <svg width="72" height="49" viewBox="0 0 72 49" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M60 24.5H48C48 5.7 64 0.333333 72 0V12C62.4 12 60 20.3333 60 24.5Z" fill="#116B11" />
              <path d="M60 24.5H72C72 43.3 56 48.6667 48 49V37C57.6 37 60 28.6667 60 24.5Z" fill="#116B11" />
              <path d="M36 24.5H24C24 5.7 40 0.333333 48 0V12C38.4 12 36 20.3333 36 24.5Z" fill="#47A747" />
              <path d="M36 24.5H48C48 43.3 32 48.6667 24 49V37C33.6 37 36 28.6667 36 24.5Z" fill="#47A747" />
              <path d="M12 24.5H0C0 5.7 16 0.333333 24 0V12C14.4 12 12 20.3333 12 24.5Z" fill="#89CD89" />
              <path d="M12 24.5H24C24 43.3 8 48.6667 0 49V37C9.6 37 12 28.6667 12 24.5Z" fill="#89CD89" />
            </svg>
          </div>
        </div>

        {/* Menu Items */}
        <div className={cn(
          "flex flex-col w-full px-[22px] overflow-y-auto",
          "transition-all duration-300",
          // Scrollbar styles
          "[&::-webkit-scrollbar]:w-2.5",
          "[&::-webkit-scrollbar-track]:bg-transparent",
          "[&::-webkit-scrollbar-thumb]:rounded-full",
          "[&::-webkit-scrollbar-thumb]:border-2",
          "[&::-webkit-scrollbar-thumb]:border-transparent",
          "[&::-webkit-scrollbar-thumb]:bg-clip-padding",
          // Show scrollbar only on hover
          isHovered 
            ? "[&::-webkit-scrollbar-thumb]:bg-gray-200 [&::-webkit-scrollbar-thumb:hover]:bg-gray-300" 
            : "[&::-webkit-scrollbar-thumb]:bg-transparent",
          // Firefox support
          isHovered 
            ? "[scrollbar-color]:gray-200 transparent" 
            : "[scrollbar-color]:transparent transparent",
          "[scrollbar-width]:thin"
        )}>
          {filteredMenuItems.map((item) => { // Use filteredMenuItems here
            const isActive = url === item.href;

            if (item.children) {
              return (
                <HoverCard key={item.id} openDelay={100} closeDelay={100}>
                  <HoverCardTrigger asChild>
                    <Link
                      href={item.href}
                      className={cn(
                        "flex flex-col items-center justify-center gap-1 p-1 rounded-xl transition-colors",
                        "min-h-[79px] w-full",
                        isActive ? "text-green-700" : "hover:text-green-600"
                      )}
                    >
                      <div className="w-5 h-5 flex items-center justify-center">
                        {item.icon}
                      </div>
                      <span className="text-center text-xs leading-normal font-urbanist">
                        {item.label}
                      </span>
                    </Link>
                  </HoverCardTrigger>
                  <HoverCardContent
                    side="right"
                    align="center"
                    className="w-56 p-2 bg-white dark:bg-neutral-900 shadow-lg border rounded-lg ml-8"
                  >
                    {item.children.map((sub, idx) => (
                      <Link
                        key={idx}
                        href={sub.href}
                        className="block px-4 py-2 rounded-md text-sm hover:bg-gray-50 hover:dark:bg-accent"
                      >
                        {sub.label}
                      </Link>
                    ))}
                  </HoverCardContent>
                </HoverCard>
              );
            }

            return (
              <Link
                key={item.id}
                href={item.href}
                className={cn(
                  "flex flex-col items-center justify-center gap-1 p-1 rounded-xl transition-colors",
                  "min-h-[79px] w-full",
                  isActive ? "text-green-700" : "hover:text-green-600"
                )}
              >
                <div className="w-5 h-5 flex items-center justify-center">
                  {item.icon}
                </div>
                <span className="text-center text-xs leading-normal font-urbanist">
                  {item.label}
                </span>
              </Link>
            );
          })}
        </div>
      </div>
    </>
    );
}